<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Falling Sand Sandbox</title>
<style>
  body{margin:0;background:#222;color:#eee;font-family:sans-serif;display:flex;flex-direction:column;align-items:center;}
  #controls{margin:10px;}
  button{background:#444;border:none;padding:6px 12px;margin:2px;color:#fff;border-radius:4px;cursor:pointer;}
  button:hover{background:#555;}
  canvas{border:1px solid #555;background:#111;}
</style>
</head>
<body>
<div id="controls">
  <button id="mat-sand">Sand</button>
  <button id="mat-water">Water</button>
  <button id="mat-wall">Wall</button>
  <button id="mat-acid">Acid</button>
  <button id="mat-empty">Eraser</button>
  <button id="clear">Clear</button>
</div>
<canvas id="sand" width="400" height="400"></canvas>

<script>
(() => {
  const canvas = document.getElementById('sand');
  const ctx = canvas.getContext('2d');
  const w = 80, h = 80; // grid size
  const cellSize = canvas.width / w;
  const materials = ['empty','sand','water','wall','acid'];
  const colors = {
    empty:'#111',
    sand:'#D4A017',
    water:'#3498db',
    wall:'#7f8c8d',
    acid:'#e74c3c'
  };
  let grid = new Array(w*h).fill('empty');
  let nextGrid = new Array(w*h);
  let currentMat = 'sand';
  const btns = {
    sand: document.getElementById('mat-sand'),
    water: document.getElementById('mat-water'),
    wall: document.getElementById('mat-wall'),
    acid: document.getElementById('mat-acid'),
    empty: document.getElementById('mat-empty')
  };
  Object.keys(btns).forEach(k=>{
    btns[k].addEventListener('click',()=>{currentMat=k;});
  });
  document.getElementById('clear').addEventListener('click',()=>{
    grid.fill('empty'); draw(); window.sim.clear();
  });

  function idx(x,y){return y*w+x;}
  function get(x,y){return (x<0||y<0||x>=w||y>=h)?'wall':grid[idx(x,y)];}
  function set(x,y,mat){if(x>=0&&y>=0&&x<w&&y<h) grid[idx(x,y)] = mat;}
  window.sim={w,h,tick, get,set,clear:()=>{grid.fill('empty');draw();}};

  function tick(n=1){
    for(let step=0;step<n;step++){
      nextGrid.set(grid);
      // process bottom-up
      for(let y=h-1;y>=0;y--){
        for(let x=0;x<w;x++){
          const i=idx(x,y), mat=grid[i];
          if(mat==='sand'||mat==='water'||mat==='acid'){
            let moved=false;
            // attempt fall
            if(get(x,y+1)==='empty'){
              nextGrid[idx(x,y+1)]=mat; nextGrid[i]='empty'; moved=true;
            }else if((mat==='sand' || mat==='acid') && (get(x,y+1)=='water')){
              nextGrid[idx(x,y+1)] = mat; nextGrid[i] = 'water'; moved=true;
            }
            // slide
            if(!moved){
              const dirs=[-1,1];
              if(Math.random()<0.5) dirs.reverse();
              for(const d of dirs){
                if(get(x+d,y+1)==='empty'){
                  nextGrid[idx(x+d,y+1)] = mat; nextGrid[i]='empty'; moved=true; break;
                }
              }
            }
            // water spread
            if(!moved && mat==='water'){
              const dirs=[-1,1];
              if(Math.random()<0.5) dirs.reverse();
              for(const d of dirs){
                if(get(x+d,y)==='empty'){
                  nextGrid[idx(x+d,y)] = 'water'; nextGrid[i]='empty'; moved=true; break;
                }
              }
            }
            // acid dissolve
            if(mat==='acid' && !moved){
              const dirs=[-1,0,1];
              for(const d of dirs){
                const nx=x+d, ny=y+1;
                if(get(nx,ny)=== 'sand' || get(nx,ny)==='wall'){
                  nextGrid[idx(x,y)] = 'empty';
                  nextGrid[idx(nx,ny)] = 'empty';
                  moved=true; break;
                }
              }
            }
          }
        }
      }
      grid.set(nextGrid);
    }
  }

  function draw(){
    for(let y=0;y<h;y++){
      for(let x=0;x<w;x++){
        const mat=grid[idx(x,y)];
        ctx.fillStyle=colors[mat];
        ctx.fillRect(x*cellSize, y*cellSize, cellSize, cellSize);
      }
    }
  }

  let painting=false;
  canvas.addEventListener('mousedown',e=>{painting=true;paint(e);});
  canvas.addEventListener('mousemove',e=>{if(painting) paint(e);});
  window.addEventListener('mouseup',()=>painting=false);

  function paint(e){
    const rect=canvas.getBoundingClientRect();
    const x=Math.floor((e.clientX-rect.left)/cellSize);
    const y=Math.floor((e.clientY-rect.top)/cellSize);
    if(x>=0&&y>=0&&x<w&&y<h){
      set(x,y,currentMat); draw();
    }
  }

  function loop(){draw(); requestAnimationFrame(loop);}
  loop();

})();
</script>
</body>
</html>
